        <RadialMenuItem value="paste" icon={<PasteIcon />}>Paste</RadialMenuItem>
        <RadialMenuItem value="delete" icon={<TrashIcon />} tone="danger">Delete</RadialMenuItem>
      </RadialMenu>
    </Stage>
  )
